"""General utilities for AgentCube SDK."""


def read_token_from_file(file_path: str) -> str:
    """Read token from file, return empty string if not found.

    Args:
        file_path: Path to the token file

    Returns:
        Token string stripped of whitespace, or empty string if file not found
    """
    try:
        with open(file_path, "r") as f:
            return f.read().strip()
    except FileNotFoundError:
        return ""
